import { formatSeriesNameForDisplay } from './format-series-name-for-display.js';
import type { SeriesName } from '../../../types.js';

export const getIsTruncated = (
  isMultiLineCssClamped: boolean,
  name: SeriesName,
  multiLine: boolean,
  nameText: SeriesName,
  displayNameText: SeriesName,
): boolean => {
  if (isMultiLineCssClamped) {
    return true;
  }

  if (Array.isArray(name)) {
    if (multiLine) {
      return name.some(
        (original, index) => original !== (nameText as string[])[index],
      );
    }
    return formatSeriesNameForDisplay(name) !== nameText;
  }

  return nameText !== displayNameText;
};
